$(document).ready(function() {
    var baseUrl = window.location.origin;
    let retrive_data = baseUrl+'/purchase_det';
    let edit_category = baseUrl+'/purchase/edit_purchase';
    // Initialize DataTable
    $('#view_purchase').DataTable({
        processing: true,
        serverSide: true,
        searching: true,
        scrollY: 500,
        scrollX: true,
        scrollCollapse: true,
        
        columnDefs: [{
            "defaultContent": "-",
            "targets": 0,
            "render": function (data, type, row, meta) {
              // Return the serial number (row index + 1)
              return meta.row + 1;
            }
          }],
        ajax: {
            url: retrive_data,
        },

        "columns": [
          { "data": null }, // This column will be used for serial numbers
             
            { 
              "data": "category_id",
            },
            { 
              "data": "subcategory_id",
            },
            { 
              "data": "detail",
            },
            { 
              "data": "amount",
            },
            { 
              "data": "date",
            },
            { 
              "data": "type",
            },
           
          { 
            title: 'Action',
            render: function(data, type, full) {
                return `
                <a href='edit_purchase_category/${full.id}'><i class="ti-pencil-alt"></i></a>
                 `;      
            }
        }

        ]
    });
});